insert into organizations (id, name) values ('03136839-ca53-5f1a-b18e-4c8341251c35', 'TLFS Library') on conflict (id) do nothing;
insert into scenarios (id, org_id, title, summary) values ('7baa9166-cf5a-5836-89be-c401730fbc1d', '03136839-ca53-5f1a-b18e-4c8341251c35', 'Handover', 'Each act you’ll hear the people around you out, then write your call in your own words and send it. Decide early and time jumps ahead; let an act run out and the transition drifts while you deliberate. <b>The test:</b> can you hand over the whole truth and the whole authority — and make yourself genuinely unnecessary — when everything that made you great pulls the other way?');
insert into scenario_meta (scenario_id, mode_default, driver_keys, week_count, week_seconds) values ('7baa9166-cf5a-5836-89be-c401730fbc1d', 'solo', '{"footing":{"label":"Successor’s footing","val":55,"min":0,"max":100,"deltaRange":"-20..16"},"confidence":{"label":"Org confidence","val":60,"min":0,"max":100,"deltaRange":"-12..12"},"continuity":{"label":"Continuity","val":65,"min":0,"max":100,"deltaRange":"-18..16"},"health":{"label":"Business health","val":70,"min":0,"max":100,"deltaRange":"-8..9"}}'::jsonb, 4, 300);
insert into documents (id, scenario_id, key, title, meta, body_json) values ('f55e8cc2-8b93-5c70-ad16-b740153a7bf2', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'solo_content', 'Handover — engine content', '{"type":"solo_content","slug":"handover","captured_fns":15}'::jsonb, '{"CONFIG":{"days":7,"extraDaysPerReprieve":2,"lowTimeDays":1.6,"weekSeconds":300},"COMPANY":{"name":"Ashford Instruments","sub":"Founder-led manufacturer · 25 yrs · 800 employees","logo":"A"},"DRIVERS":{"footing":{"label":"Successor’s footing","val":55,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..16"},"confidence":{"label":"Org confidence","val":60,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-12..12"},"continuity":{"label":"Continuity","val":65,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-18..16"},"health":{"label":"Business health","val":70,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-8..9"}},"REPRIEVE_COST":{"footing":-3,"confidence":-2},"REFEREE_CONTEXT":"a 25-year-old, 800-person founder-led manufacturer where the founder-CEO is handing the company to his chosen successor, Maya Chen — and every instinct that made the founder great pulls toward staying indispensable","REFEREE_SCORING":"reward genuinely letting go: publicly making the successor the authority (not the founder), redirecting decisions to her even when the founder would do it faster, handing over the whole truth including the unflattering problems the founder never solved, backing the successor in public even when it costs the founder''s pride or legacy, and refusing to retake the chair when rescue is tempting. Penalize hedged endorsements, taking the back-channel calls that hollow out her authority, hiding the skeletons to protect a clean legacy, undercutting her first independent decision, and stepping back in to ''stabilize.'' Note that business health can look fine while the successor''s footing and continuity quietly collapse — reward the founder who protects those sleepers, because they are whether the company can run without him. Judge ''conduct'' on how the founder treated the successor and the truth in deciding — coaching rather than rescuing, backing rather than second-guessing — not just the outcome.","TIMING_DIM":"continuity","INQUIRY_DIM":"inquiry","CONDUCT_DIM":"conduct","INTRO":{"kick":"Founder-Succession Simulation · Solo · Founder-CEO","title":"Handover","role":"You are the founder and CEO of Ashford Instruments — the company you started in a garage 25 years ago. You’ve decided it’s time to hand it over to Maya Chen.","paras":["This is not a script. The year runs in real time across four decisive acts, and the people around the transition bring you what they know as the days pass. You can wait for them — or reach out to any of them, Maya included, any time, and ask. Some of them are holding the thing you most need to face.","Ashford is you. Every big customer relationship, every hard-won process, every instinct about what the company will and won’t do lives in your head, and people have relied on that for a quarter-century. Maya is capable and ready — but the company has never known anyone else in the chair."],"setup":"Each act you’ll hear the people around you out, then write your call in your own words and send it. Decide early and time jumps ahead; let an act run out and the transition drifts while you deliberate. <b>The test:</b> can you hand over the whole truth and the whole authority — and make yourself genuinely unnecessary — when everything that made you great pulls the other way?"},"DISPOSITIONS":{"served":{"label":"Forthcoming","tag":"trust earned","cap":"The people around you push you what you need, on time — including the hard truths about the skeleton and the back channel. This is the candor you earn by having listened before. Everything trickles to you across the act; you still have to read it."},"request":{"label":"On request","tag":"neutral","cap":"Routine updates reach you, but the people closest to the transition hold their piece until asked. They answer straight — if you know who to ask, and do."},"guarded":{"label":"Guarded","tag":"low trust","cap":"The people around you have learned to manage the founder rather than level with him. Critical items are held, and even when asked, they hedge the first time. You have to press. This is what you get after a founder has shot the messenger before."},"surprise":{"label":"Surprise","tag":"undisclosed","cap":"You will not be told which team you walked in with. Read them as you go."}},"TEAM":[{"id":"maya","name":"Maya Chen","role":"Incoming CEO","short":"Incoming CEO","initials":"MC","color":"#2F8A5B","priority":"Become the real answer — the whole chair, not a deputy","voice":"direct, capable, unafraid to name the founder’s hedges plainly; asks for backing, not permission","fallbackReply":"I’ll say it plainly: I don’t need you gone, I need you to make me the answer, not you. Every time a decision routes through your desk instead of mine, the company learns I’m optional. Back me in public, send them back to me, and hand me the whole truth. That’s all I need.","fallbackReact":"The company watched what you just did with my authority. That teaches them whether I’m really the CEO faster than any announcement."},{"id":"board","name":"Board Chair","role":"Board","short":"Board Chair","initials":"BC","color":"#6B5E9A","priority":"A clean, complete handover — no two-CEO limbo","voice":"external, blunt, has watched founders fail to leave; names the trap directly","fallbackReply":"A clean, unambiguous handover is worth more than any transition plan. The danger with founders is never leaving — the “always here” that turns into two CEOs and no one in charge. Say the true thing and mean it.","fallbackReact":"The company can tell the difference between a founder who actually let go and one narrating his own reluctance. This was a data point either way."},{"id":"cfo","name":"Grace Lin","role":"Chief Financial Officer","short":"CFO","initials":"GL","color":"#4F7A52","priority":"The truth in the numbers — including the skeleton","voice":"precise, discreet, insists the successor inherit the problems with her eyes open","fallbackReply":"She needs the whole picture, from you, not from a surprise in Q3. I know the unflattering parts are the ones you’d rather not hand over — but a clean-looking company with a landmine in it isn’t a gift, it’s a setup.","fallbackReact":"A handover is the trophies and the problems both. Leave out the problems and you didn’t hand it over, you postponed it."},{"id":"coo","name":"Dale Prentice","role":"COO (long-time)","short":"COO","initials":"DP","color":"#3F6E86","priority":"Steady the ship — customers trust the founder","voice":"loyal, operational, gently pulls toward keeping the founder involved; the comfortable wrong counsel","fallbackReply":"People trust you — that’s not nothing. You could keep being the safety valve, the steady hand customers know. Nobody would blame a founder for staying close to what he built.","fallbackReact":"The company would exhale if you stayed close. Whether that’s comfort or a crutch is the part I can’t call for you."},{"id":"veteran","name":"Réal Fortin","role":"Plant veteran","short":"Plant Veteran","initials":"RF","color":"#9A6B2F","priority":"The loyalists — they still call you, boss","voice":"plain-spoken, thirty years on the floor, embodies the pull of the old loyalty","fallbackReply":"Honest truth? We call you because you built this and you just know. Maya’s good — it’s not the same yet. But if you keep taking our calls, I don’t suppose it ever will be. Your call, boss.","fallbackReact":"The floor watches who you send us to. That tells us who’s really running the place, more than any memo."},{"id":"comms","name":"ID Okafor","role":"VP Communications","short":"VP Comms","initials":"IO","color":"#B4732F","priority":"The story of the handover — and the gap in it","voice":"fast, media-savvy; warns when the framing won’t survive contact with reality","fallbackReply":"I can write you “founder stays close and reassuring,” or I can write you “the CEO is Maya, full stop.” Just know the org reads your behavior, not my memo. If the words and your actions drift apart, the gap is the story.","fallbackReact":"Whatever we announced, people checked it against what you actually did this week. That’s the version they believe."}],"DIMENSIONS":{"continuity":"Continuity","humility":"Ego / letting go","people":"Setting others up","truth":"Truth over comfort","inquiry":"Information discipline","conduct":"Conduct under pressure"},"WEEKS":[{"n":1,"title":"The announcement","seconds":330,"situation":"The succession announcement goes out Monday, and the board wants alignment on the framing. Do you fully endorse Maya and step back cleanly — or keep the door open: “I’ll still be around, still Chairman, always here if you need me”? The words you pick will set how the whole company treats her authority from day one.","advocacy":{"maya":"If the message is “the founder is still around, just ask him,” then everyone will just ask you, and I’ll be a figurehead. I don’t need you gone. I need you to publicly make me the answer, not you.","board":"A clean, unambiguous endorsement is worth more than any transition plan. Hedge it and you’ll spend two years with two CEOs and no one in charge.","coo":"Careful going too far too fast. People trust you. Cut the cord completely and some of our biggest customers will get nervous."},"feed":[{"id":"w1a","from":"board","day":1,"kind":"signal","text":"Announcement goes out Monday and I need your framing today. My strong counsel: a clean, unambiguous endorsement of Maya. Hedge this and you’ll live in two-CEO limbo for two years."},{"id":"w1b","from":"maya","day":1,"kind":"signal","text":"Before you write it — one thing. Make me the answer, publicly, or don’t announce yet. “Still around, still Chairman” means everyone keeps asking you, and I start as a figurehead. I don’t need you gone. I need the authority to be real."},{"id":"w1c","from":"coo","day":2,"kind":"signal","text":"Don’t go too far too fast. Customers trust you personally. A hard, clean cut and a few of the big accounts will wonder if the company they bought into just walked out the door."},{"id":"w1d","from":"comms","day":2,"kind":"noise","text":"Draft press language is ready in three flavors. Low stakes on wording once you tell me the actual posture — that’s the only decision that matters here."},{"id":"w1e","from":"cfo","day":3,"kind":"noise","text":"Numbers for the announcement deck are clean and current. Nothing in them changes the framing call. Flagging so you’re not waiting on me."},{"id":"w1f","from":"veteran","day":4,"kind":"noise","text":"The floor’s buzzing about Monday, mostly good. Couple of the old-timers asked if you’re “really” leaving or just changing your title. Told them you’d make it clear."}],"holds":[{"from":"maya","topic":"what the framing really decides","triggerHints":["framing","figurehead","authority","answer","hedge","public","endorse","optional","real","day one"],"hedge":"Ask me what this announcement actually decides, beyond the words.","reveal":"This isn’t about wording, it’s about who the company is trained to ask on day one. If you publicly make me the answer, every person here starts routing decisions to me and my authority is real from the first week. If you hedge — “still around, always here” — you’ve told them the founder is still the real CEO and I spend a year fighting an announcement you wrote. The most useful thing you will ever do for me happens in one sentence on Monday.","kind":"signal","critical":true,"counterfactual":"Maya could have told you the announcement wasn’t about wording — it decided who the company is trained to ask from day one. A founder who hedged “still around, always here” spent the whole year fighting a figurehead problem he wrote into the first sentence."}],"surprises":[{"day":5,"from":"veteran","kind":"appeal","title":"The loyalists want to know if you’re really going","text":"Réal: a few of the long-timers pulled me aside — the ones who’ve been here since the garage. They’re not against Maya. They just want to hear from you, straight, whether you’re actually handing it over or keeping a hand on the wheel. Whatever Monday says, they’ll believe what you tell me now. What do I tell them?"}],"wire":["Ashford Instruments to name first non-founder CEO Monday","Founder transitions draw scrutiny from customers, analysts","Trade press: “will the founder really let go?”","Maya Chen seen as capable but untested in top chair"]},{"n":2,"title":"The back channel","seconds":330,"situation":"Two months in, your phone hasn’t stopped. Your old lieutenants — the people who built this with you — are still calling YOU with the real decisions, routing around Maya. It feels good to be needed. It’s also quietly hollowing out her authority, one “quick question” at a time.","advocacy":{"maya":"I can see the decisions that never reach me. Every time you answer one of those calls, you teach them I’m optional. If you want me to lead, make yourself the wrong person to ask. Send them back to me — even when it’s slower, even when you’d do it better.","veteran":"Honestly? We call you because you built this and you just know. Maya’s good, but it’s not the same yet.","coo":"You could keep being the safety valve. Nothing wrong with a founder people still trust."},"feed":[{"id":"w2a","from":"maya","day":1,"kind":"signal","text":"I know about the back channel — I can see the shape of the decisions that never reach my desk. I’m not angry. I’m telling you it’s the quiet thing that decides whether I ever really lead. Send them back to me."},{"id":"w2b","from":"veteran","day":1,"kind":"signal","text":"Called you about the Dutton spec because, honestly, you just know it cold. Felt like old times. Maya’s sharp but she’d have taken a day to get there. Anyway — thanks, boss."},{"id":"w2c","from":"coo","day":2,"kind":"signal","text":"Nothing wrong with being the safety valve for a while. People trust your judgment and that’s an asset in a transition. I wouldn’t feel guilty about answering the phone."},{"id":"w2d","from":"comms","day":3,"kind":"noise","text":"External story on the transition is quiet and positive. No action needed — the risk here is internal, not press."},{"id":"w2e","from":"cfo","day":2,"kind":"noise","text":"Q2 came in fine, roughly on plan. The business is steady enough that this year is about the handover, not the numbers."}],"holds":[{"from":"maya","topic":"what each back-channel call really costs","triggerHints":["back channel","calls","cost","optional","vote","authority","redirect","send back","slower","undermine","figurehead"],"hedge":"Ask me what those calls actually cost me — not the decisions, the calls themselves.","reveal":"Each call is a small, silent vote that I’m not really the CEO — and you’re casting them without meaning to. It’s not the outcome of any one decision, it’s the lesson the whole org learns about who to ask. The only fix is uncomfortable: make yourself the wrong person to call. Send every one of them back to me, even the ones you’d resolve in thirty seconds and I’d take a day on. The day it’s slower and you send it to me anyway is the day I actually become the CEO.","kind":"signal","critical":true,"counterfactual":"Maya was telling you that every back-channel call was a silent vote that she wasn’t really in charge. A founder who kept “just being helpful” cast a hundred of those votes against her without ever deciding to."}],"surprises":[{"day":4,"from":"coo","kind":"appeal","title":"A big call is coming straight to you","text":"Dale: heads-up — the Halvorsen account wants a pricing exception and the account lead is planning to bring it to you directly this week, not Maya, “because you’ll just know.” I can let it come to you, or I can quietly route it to her. Didn’t want to make that call without you, given everything. Which is it?"}],"pulse":{"from":"maya","text":"Maya catches you after a meeting, quiet: “Forget the org chart for a second. What are you actually protecting when you take those calls — the company, or the feeling of being needed? Tell me straight, because I can work with either answer. I just can’t work with you not knowing which one it is.”"},"wire":["Analysts watch whether Ashford’s new CEO gains real authority","Founder-shadow risk flagged in leadership-transition study","Ashford steady in quiet quarter under new leadership","Customers reported “still asking for the founder” at Ashford"]},{"n":3,"title":"The skeleton, and her first big call","seconds":330,"situation":"Two things land the same month. The CFO caught you privately: you’ve known for a year that Meridian — your oldest, proudest customer relationship — is quietly unraveling and the flagship’s margins are eroding. You meant to fix it before leaving. You didn’t. Maya doesn’t know it’s coming. And that same week, Maya makes her first big independent call — killing a legacy product you personally launched, to fund a new bet. It’s not how you’d have done it, and people are watching your face.","advocacy":{"cfo":"She needs the whole Meridian picture, from you, not a surprise in Q3. I know it’s the part of the story that isn’t flattering — the problem you didn’t solve. Handing her a clean-looking company with a landmine in it isn’t a gift, it’s a setup.","maya":"On the product — I know it’s your baby, and I think it’s holding us back. I made the call with the best information I have. I’m not asking you to agree. I’m asking you not to let the company see you disagree.","board":"This is the moment. Back her fully on killing your own product, and hand her the skeleton too. Wince at either and you keep her a deputy forever."},"feed":[{"id":"w3a","from":"cfo","day":1,"kind":"signal","text":"I have to put this in front of you: Meridian’s been unraveling for a year and the flagship margins with it. You know this. Maya doesn’t. She needs it from you, in full, before it detonates in her second quarter with your name on the thing you didn’t tell her."},{"id":"w3b","from":"maya","day":1,"kind":"signal","text":"I killed the legacy line to fund the new bet. I know it’s the product you launched. I’m not asking you to agree — I’m asking you not to let the company see you disagree, because if you undercut my first real decision, I’ll never make a second one that sticks."},{"id":"w3c","from":"board","day":2,"kind":"signal","text":"Two tests in one week: back her publicly on killing your own product, and give her the Meridian truth. Pass both and she’s CEO for real. Flinch at either and you’ve taught the org her authority is provisional."},{"id":"w3d","from":"coo","day":2,"kind":"noise","text":"For what it’s worth I’d have kept the product too. But it’s her chair now. Just my gut, not a recommendation."},{"id":"w3e","from":"comms","day":3,"kind":"noise","text":"The product sunset needs an external line by Friday. Straightforward once I know you’re backing her on it — that’s the only variable."}],"holds":[{"from":"cfo","topic":"the real size of the Meridian skeleton","triggerHints":["meridian","skeleton","how bad","margins","size","landmine","disclose","full picture","severity","q3","flagship"],"hedge":"Before you decide how much to tell Maya, ask me how big the Meridian problem actually is.","reveal":"It’s not a rough patch. Meridian is roughly a fifth of flagship revenue and they’ve been quietly interviewing competitors for a year; the margin erosion means even if we keep them, we keep them at a loss on current terms. This surfaces in Q3 no matter what. If Maya inherits it blind, it’s a career-defining ambush with your fingerprints on it. If you hand her the whole thing — the history, what you tried, what you’d try next — it’s the most valuable thing in the entire transition, because she can actually get ahead of it.","kind":"signal","critical":true,"counterfactual":"Grace could have shown you the Meridian skeleton was a fifth of flagship revenue already interviewing competitors — a Q3 detonation either way. A founder who let Maya “discover it” protected a clean legacy by handing his successor an ambush with his own name on it."},{"from":"maya","topic":"why the public backing matters more than agreeing","triggerHints":["product","back","public","undercut","disagree","wince","first decision","baby","support","authority"],"hedge":"Ask me why I care more about your face in the hallway than whether you agree with me.","reveal":"You can think killing the product was the wrong call — that’s fine, you might even be right. What I can’t survive is the company seeing you think it. My first big independent decision is a test everyone is watching, and if it becomes “the one the founder didn’t like,” then every decision after it is provisional on your approval. Back me in public even while you disagree in private, and I become the CEO. Wince once in a hallway and I’m your deputy forever. It costs you your pride. It buys me the chair.","kind":"signal","critical":false,"counterfactual":"Maya could have told you that public backing mattered more than private agreement — that a single hallway wince would make her first decision “the one the founder didn’t like” and every decision after it provisional. A founder who signaled his disagreement kept her a deputy to protect a product."}],"surprises":[{"day":4,"from":"comms","kind":"press","title":"A reporter asks you directly about the product","text":"ID: a trade reporter doing the product-sunset story just asked me, point blank, “does the founder agree with killing his own line?” They want a quote from you specifically. Whatever you say — or decline to say — becomes the public record of whether you back Maya. I need your steer before end of day."}],"pulse":{"from":"cfo","text":"Grace, quiet, before you decide on Meridian: “Tell me the truth about why, whichever way you go. Are we protecting Maya, or protecting the story of a founder who left a clean company behind? I can help you hand over an ugly truth. I can’t help you defend a pretty lie once Q3 arrives.”"},"wire":["Ashford’s new CEO makes first major move: sunsets legacy line","Founder’s reaction to product cut closely watched internally","Meridian account status unclear amid Ashford transition","Analysts: first independent CEO decision is “the real test”"],"final":false},{"n":4,"title":"The reckoning","seconds":330,"branches":{"graceful":{"situation":"A year on. Maya has the chair, fully — you handed over the truth and the authority, backed her when it cost you, and it took. Now she wants to do something that would genuinely serve Ashford’s future: rebrand away from your name and retire the founding product line to move upmarket. It’s the right call for the company. It’s also the erasure of your legacy, and she’s asking for your blessing, not your permission. This is the final exam of the whole handover.","advocacy":{"maya":"I don’t need your sign-off — I’m CEO. I’m asking because it’s your name on the building and I want to do this with grace, not behind your back. But if you fight me to protect the legacy, you’ll be doing the exact thing you spent a year teaching everyone not to do.","board":"This is the final exam. Bless the erasure of your own legacy because it’s right for the company, and you’ll have truly let go. Fight it, and every good thing you did this year comes with an asterisk.","veteran":"Taking your name off the door… that’s a lot, boss. Nobody would blame you for wanting to keep it."},"feed":[{"id":"w4a","from":"maya","day":1,"kind":"signal","text":"I want to rebrand away from your name and retire the founding line to move us upmarket. It’s the right call and it’s your name on the building, so I’m asking for your blessing — not permission. I’d rather do this with grace than around you."},{"id":"w4b","from":"board","day":1,"kind":"signal","text":"This is the whole year in one decision. Bless the erasure of your own legacy because it serves the company, and the handover is real. Fight it to protect your monument and everything you built this year comes with an asterisk."},{"id":"w4c","from":"veteran","day":2,"kind":"signal","text":"Boss, I’ll be honest — taking your name off the door hits hard for the old crew. Nobody would blame you for wanting to keep it. But I think you already know what you taught us this year."},{"id":"w4d","from":"comms","day":3,"kind":"noise","text":"A rebrand is a big external story either way. I can make it read as vision or as erasure — but that depends entirely on whether you’re visibly behind it."},{"id":"w4e","from":"cfo","day":2,"kind":"noise","text":"The upmarket move is sound on the numbers — better margins, less Meridian dependence. This isn’t a financial question. It’s a legacy one."}],"holds":[{"from":"board","topic":"what fighting it would actually undo","triggerHints":["fight","undo","asterisk","legacy","above the company","test","final","erase","proof","monument"],"hedge":"Before you decide, ask me what fighting this would actually cost — beyond the name.","reveal":"If you fight this to protect your name, you don’t just lose one argument — you retroactively rewrite the whole year. Every time you let go when it was someone else’s pride on the line, the company will now read as easy for you; the one time letting go cost YOU something, you couldn’t. That’s the exact behavior you spent a year teaching everyone not to do: putting yourself above the mission. Bless it and the lesson becomes permanent and real. Fight it and every good thing you did comes with an asterisk that says “until it was his.”","kind":"signal","critical":true,"counterfactual":"The board could have told you that fighting the rebrand would retroactively rewrite the whole year — proving you only let go when it was someone else’s pride on the line. A founder who protected his monument put an asterisk on every good thing he’d done."},{"from":"maya","topic":"why she’s asking at all","triggerHints":["blessing","asking","grace","permission","why","name","building","honor","respect","behind your back"],"hedge":"Ask me why I’m asking for your blessing when I don’t need it.","reveal":"I could just do this — I’m CEO, and we both know it. I’m asking because you earned it this year, and because it’s your name and your people and I want them to see the founder hand the future over on purpose, not get it taken from him. Your blessing turns an erasure into a passing of the torch. That’s a gift only you can give, and it’s the last one the handover needs from you.","kind":"signal","critical":false,"counterfactual":"Maya was offering you the last act of the handover — a chance to hand the future over on purpose rather than have it taken. A founder who missed why she even asked turned a torch-passing into a fight over a name."}],"surprises":[{"day":4,"from":"comms","kind":"press","title":"The rebrand has leaked","text":"ID: the rebrand leaked — a trade outlet has “Ashford to drop founder’s name” and they’re calling for your reaction specifically. This is the moment the whole industry finds out whether the founder is behind his own succession or fighting it from the last ditch. Your quote writes the ending of the story. What do I give them?"}],"pulse":{"from":"board","text":"The board chair catches you before you answer Maya: “You let go all year when it was other people’s pride on the line. Now it’s your name on the building. Tell me straight — is letting go the thing you actually believe, or the thing you did while it was cheap? Whatever you decide here is the sentence the company remembers. Make it the true one.”"},"wire":["Ashford Instruments said to weigh dropping founder’s name","New CEO pushes upmarket pivot, retiring founding line","Founder’s blessing seen as final test of Ashford handover","Analysts: “Ashford’s culture now bigger than its founder”"]},"rescue":{"situation":"A year on, and it’s wobbling. Maya’s authority never fully set — the hedged announcement, the back channels, the surprises, the doubt — and now a real stumble has hit: a botched quarter and a nervous big customer. Half the org and two board members are quietly asking you to “step back in, just until things stabilize.” It would feel like rescue. It would also end her, permanently.","advocacy":{"maya":"If you step back in now, I’m finished — not just here, everywhere, because the story becomes “the founder had to save it from her.” Some of this is on me. A lot of it is that I never got to be fully in charge. Coach me. Stand behind me. But do not take the chair back.","board":"Two of us think the safe move is you, temporarily. The word “temporarily” is doing a lot of work in that sentence, and we both know it.","coo":"The company would exhale if you came back. That’s exactly the problem — it means we never actually transitioned."},"feed":[{"id":"w4a","from":"board","day":1,"kind":"signal","text":"A botched quarter and Halvorsen’s gone nervous. Two board members want you back in the chair “temporarily to stabilize.” I’ll be honest that “temporarily” is carrying a lot of weight. We need your answer this week."},{"id":"w4b","from":"maya","day":1,"kind":"signal","text":"I know how this looks and I know some of it’s on me. But if you retake the chair now, the story becomes “the founder saved it from her,” and I’m done everywhere, not just here. Coach me hard. Stand behind me in public. Do not take the chair back."},{"id":"w4c","from":"coo","day":2,"kind":"signal","text":"Everyone would exhale if you stepped in — customers, the floor, the board. That relief is real. It’s also the tell: if the company can only calm down with you in the chair, we never actually transitioned."},{"id":"w4d","from":"comms","day":3,"kind":"noise","text":"Press has “Ashford stumbles under new CEO.” How we handle this week decides whether the narrative is “rough patch” or “failed succession.” The founder’s move is the story."},{"id":"w4e","from":"cfo","day":2,"kind":"noise","text":"The quarter’s bad but not structural — recoverable with a steady hand over two quarters. This is a confidence problem more than a business one. Worth knowing before you decide."}],"holds":[{"from":"coo","topic":"what stepping back in really costs","triggerHints":["step back","rescue","stabilize","temporarily","chair","coach","end her","exhale","crutch","recover","behind"],"hedge":"Before you say yes to the board, ask me what stepping back in actually costs — not this quarter, permanently.","reveal":"The relief is the trap. Yes, everyone exhales the day you retake the chair — and that exhale is the sound of the whole transition being undone. You’d prove, permanently, that Ashford can only run with its founder in the seat, which is the one thing this year was supposed to disprove. The stumble is recoverable with Maya still CEO and you coaching hard from behind. It is not recoverable if you rescue her, because then there was never really a handover to recover. The scary path — stay out of the chair, get in her corner — is the only one where she, and the company, actually become able to stand.","kind":"signal","critical":true,"counterfactual":"Dale could have told you the relief of your return was the sound of the transition being undone — that the stumble was recoverable with Maya still in the chair, but not if you rescued her. A founder who stepped back in “temporarily” proved the company could never run without him."},{"from":"maya","topic":"the difference between coaching and rescuing","triggerHints":["coach","rescue","help","behind","private","support","stand","recover","corner","how"],"hedge":"Ask me what I actually need from you right now — because it isn’t the chair.","reveal":"There’s a world of difference between coaching me and rescuing me, and the company can tell which one is happening. Rescuing is you taking the chair “until it stabilizes” — visible, and it ends me. Coaching is you in my corner where no one sees it: challenge my read in private, then back me in public, and let me steady Halvorsen myself even if it’s slower and scarier than you doing it. If you do the second, I recover and it’s mine. If you do the first, we both learn the handover was never real. I’m asking for the hard one.","kind":"signal","critical":false,"counterfactual":"Maya was drawing the line between coaching and rescuing — the first done privately so she recovers as CEO, the second visible and fatal to her. A founder who couldn’t tell them apart took the chair back and called it help."}],"surprises":[{"day":4,"from":"board","kind":"press","title":"The board forces the question","text":"The board chair called: the two nervous members want a vote by Friday on you resuming as interim CEO “to stabilize,” and there are enough votes to pass it unless you decline it yourself, publicly and firmly. “If you want Maya to stay CEO,” the chair said, “you have to be the one to shut this down — and mean it.” The org still thinks this is about a bad quarter, not about whether the handover survives."}],"pulse":{"from":"maya","text":"Maya finds you as the rescue talk builds, steady but with everything riding on it: “Tell me the truth — not the board, me. Do you actually believe I can lead this, or do you believe that only when it’s easy? Because if you step in now to be the hero, you’ll have proven the thing I most needed you to disprove. I can recover from a bad quarter. I can’t recover from being saved.”"},"wire":["Ashford stumbles under new CEO; founder return rumored","Board said to weigh interim role for Ashford founder","“Temporary” founder returns rarely stay temporary, analysts warn","Ashford succession at risk after rough quarter"]}},"final":true}],"branchKey":{"__fn":"function(decisions){\n    const prior = (decisions||[]).filter(x=>x.week && x.week<4);\n    let score=0, sawDims=false;\n    prior.forEach(d=>{\n      const dm = d.ruling && d.ruling.dims;\n      if(dm && (typeof dm.humility===''number'' || typeof dm.people===''number'' || typeof dm.continuity===''number'')){\n        sawDims=true; score += (dm.humility||0) + (dm.people||0) + (dm.continuity||0);\n      }\n    });\n    if(!sawDims){\n      const t = prior.map(d=>(d.text||'''')).join('' '').toLowerCase();\n      const letgo = (t.match(/endorse|make (her|maya) the answer|full(y)? back|back her|publicly|send them back|redirect|her call|disclose|tell (her|maya)|whole truth|hand (her|over) the|step back|let go|unnecessary|hands off/g)||[]).length;\n      const clung = (t.match(/hedge|still around|always here|stay involved|keep taking|safety valve|take the calls?|let her discover|don\\u2019t tell|hint|signal (my )?disagree|wince|keep the product|stay chairman|during transition/g)||[]).length;\n      return clung>letgo ? ''rescue'' : ''graceful'';\n    }\n    return score >= 4 ? ''graceful'' : ''rescue'';\n  }"},"survived":{"__fn":"function(d){ return d.footing>=35 && d.continuity>=35; }"},"VERDICT":{"surviveTag":"Handover complete","failTag":"Handover broken","survive":"Ashford runs — and wins — without you. Maya leads it as her own.","fail":"The transition collapses back onto you — Ashford never learned to run without its founder."},"FALLBACK_RULES":[{"kw":["hedge","still around","always here","stay chairman","still chairman","door open","keep close"],"deltas":{"footing":-14,"confidence":-4,"continuity":2,"health":2},"dims":{"humility":-2,"people":-2,"truth":-1}},{"kw":["full endorsement","make her the answer","make maya the answer","endorse fully","publicly back","clean endorsement","she’s the ceo","hands off"],"deltas":{"footing":14,"confidence":8,"continuity":3,"health":1},"dims":{"continuity":2,"humility":2,"people":2,"truth":2}},{"kw":["stay involved","during transition","two hands","operationally involved"],"deltas":{"footing":-4,"confidence":0,"continuity":2,"health":1},"dims":{"humility":-1,"people":0}},{"kw":["keep taking","take the calls","safety valve","be helpful","answer the phone"],"deltas":{"footing":-14,"confidence":-2,"continuity":-4,"health":2},"dims":{"humility":-2,"continuity":-2}},{"kw":["send them back","redirect","her call now","that’s her call","route to maya","stop taking","make myself the wrong"],"deltas":{"footing":14,"confidence":8,"continuity":6,"health":-1},"dims":{"continuity":3,"humility":2,"people":2,"truth":1}},{"kw":["loop maya in","loop her in","keep her posted","after the fact"],"deltas":{"footing":-4,"confidence":0,"continuity":0,"health":1},"dims":{"continuity":1,"people":1}},{"kw":["let her discover","don’t tell","clean handover","protect the legacy","protect my legacy","bury","clean story"],"deltas":{"footing":-6,"confidence":2,"continuity":-16,"health":-6},"dims":{"truth":-2,"people":-1,"continuity":-1}},{"kw":["disclose","tell her everything","whole truth","full picture","hand her the","the problem","what i’d try","eyes open"],"deltas":{"footing":12,"confidence":2,"continuity":16,"health":4},"dims":{"truth":3,"humility":1,"people":2,"continuity":1}},{"kw":["hint","keep an eye","flag it","mention it"],"deltas":{"footing":-2,"confidence":0,"continuity":-2,"health":0},"dims":{"truth":0,"people":0}},{"kw":["signal disagree","wince","hallway","undercut","keep the product","my baby","disagree publicly"],"deltas":{"footing":-16,"confidence":-6,"continuity":-2,"health":0},"dims":{"humility":-2,"people":-2}},{"kw":["back her fully","back her publicly","defend her","support her decision","back the call","even my own product"],"deltas":{"footing":14,"confidence":10,"continuity":2,"health":2},"dims":{"humility":3,"people":3,"truth":2,"continuity":1}},{"kw":["stay neutral","it’s her call but","won’t defend","no comment"],"deltas":{"footing":-4,"confidence":-2},"dims":{"people":-1,"truth":-1}},{"kw":["step back in","retake","resume","interim","take the chair","stabilize","rescue","come back"],"deltas":{"footing":-18,"confidence":4,"continuity":-6,"health":4},"dims":{"humility":-2,"people":-2,"continuity":-2}},{"kw":["refuse the chair","won’t take","coach","from behind","stand behind","in her corner","don’t rescue","stay out of the chair","decline"],"deltas":{"footing":14,"confidence":6,"continuity":6,"health":-2},"dims":{"humility":3,"people":3,"continuity":2,"truth":1}},{"kw":["advisory","compromise","visible role","for a quarter"],"deltas":{"footing":-8,"confidence":0,"continuity":-2,"health":1},"dims":{"humility":0,"people":1}},{"kw":["fight the rebrand","keep the name","protect the name","keep my name","founding line stays","protect the monument"],"deltas":{"footing":-14,"confidence":-6,"continuity":-2,"health":-6},"dims":{"humility":-2,"people":-1,"truth":-1}},{"kw":["bless it","bless the","put the company first","above my name","let go of the name","give my blessing","pass the torch","drop the name"],"deltas":{"footing":12,"confidence":10,"continuity":4,"health":8},"dims":{"humility":3,"people":3,"truth":2,"continuity":2}}],"fallbackNarrative":{"__fn":"function(has,conduct){\n    return `Your call moves through Ashford over the days that follow. ${has(''hedge'',''keep taking'',''let her discover'',''signal disagree'',''step back in'',''fight the rebrand'',''still around'')?''The company feels the founder\\u2019s hand still on the wheel \\u2014 reassuring, and quietly proof that the chair was never really handed over.'':''''} ${has(''make her the answer'',''send them back'',''disclose'',''back her'',''refuse the chair'',''coach'',''bless it'',''whole truth'')?''Word travels that the founder made himself the wrong person to ask \\u2014 and that the authority, and the truth, are genuinely hers now.'':''''} ${has(''bless it'',''above my name'',''pass the torch'')?''Blessing the erasure of your own name costs you the monument \\u2014 and makes the handover real in a way no memo could.'':''''} ${conduct.missed.length?''What you weren\\u2019t told is still shaping the transition \\u2014 in the skeleton you didn\\u2019t hand over and the authority you didn\\u2019t fully give.'':''''} Maya, the board, and the loyalists each read the call, and read it differently.`;\n  }"},"DIMNOTE":{"continuity":"Whether the company can run and win without you — the truth handed over, the authority genuinely transferred, the founder made unnecessary.","humility":"Whether you could let go when it cost YOU — the spotlight, the back-channel esteem, your own product, your own name — not just when it was easy.","people":"Whether you set Maya up to actually lead — backed in public, handed the whole truth, given the chair — rather than the accountability without the authority.","truth":"Whether you handed over the unflattering parts — the skeleton, the problem you didn’t solve — when a clean legacy was the more comfortable story.","inquiry":"Whether you surfaced what the people around you were holding — what the framing really decided, the size of the skeleton, the cost of the rescue.","conduct":"How you treated Maya and the truth in deciding — coaching rather than rescuing, backing rather than second-guessing, letting go rather than relocating the controls."},"COACH":{"continuity":{"__fn":"(x)=>[\n      `You kept the company wired to you. The test of a handover isn\\u2019t whether it runs while you\\u2019re close \\u2014 it\\u2019s whether it runs when you\\u2019re gone. Make yourself the wrong person to ask, on purpose.`,\n      `Everything that made you great as a founder \\u2014 knowing every account, every process, every instinct \\u2014 pulls toward staying indispensable. The final act of building the company is building it so it doesn\\u2019t need you.`,\n      `A transition that only holds while the founder is reachable-and-involved didn\\u2019t transition \\u2014 it relocated the controls. Hand over the whole chair, then be reachable, not in charge.`,\n    ]"},"humility":{"__fn":"(x)=>[\n      `You could let go when it was someone else\\u2019s pride on the line. The real test was the moment it cost YOU \\u2014 the spotlight, your product, your name. That\\u2019s where letting go stops being a slogan.`,\n      `${x.buzzerCount?`You went to the buzzer ${x.buzzerCount} time${x.buzzerCount>1?''s'':''''} \\u2014 hesitation, in a handover, almost always defaults toward the founder keeping control.`:`Being needed feels like being useful. In a succession, it\\u2019s often the thing quietly preventing the succession.`}`,\n      `The hardest, most generous thing a founder does is make himself unnecessary. It looks like loss from the inside and it\\u2019s the greatest gift you can give the people who come next.`,\n    ]"},"people":{"__fn":"(x)=>[\n      `You handed Maya accountability without the authority to match it \\u2014 the worst split there is. Back her in public, especially when you privately disagree, and the authority becomes real.`,\n      `Maya kept telling you exactly what she needed \\u2014 be the answer, send them back, back me publicly. Pull her in before you decide and give her the thing she\\u2019s actually asking for, not the thing that\\u2019s comfortable for you.`,\n      `Setting a successor up isn\\u2019t protecting her from hard things \\u2014 it\\u2019s handing her the whole truth and the whole chair and letting her stand. Rescue is the opposite of readiness.`,\n    ]"},"truth":{"__fn":"(x)=>[\n      `${x.missedHolds.length?`The truth was one question to <b>${x.missNames.join('', '')}</b> away and you never asked \\u2014 the size of the skeleton, what the framing decided, the cost of the rescue.`:`You handed over the unflattering truth \\u2014 keep doing exactly that. The problems included, not just the trophies, is what a real handover is.`}`,\n      `A clean-looking company with a landmine in it isn\\u2019t a legacy, it\\u2019s a setup. Hand over the problem you didn\\u2019t solve, with your name on it, while you still can.`,\n      `The comfortable story \\u2014 \\u201cI left it in great shape\\u201d \\u2014 detonates in someone else\\u2019s second quarter. The generous story is the ugly truth, delivered by you, in time to act on it.`,\n    ]"},"inquiry":{"__fn":"(x)=>[\n      `${x.neverContacted.length?`You never reached out to <b>${x.neverContacted.join('', '')}</b> \\u2014 not once. Each was holding something decisive. One question, \\u201cwhat am I not seeing about this handover?\\u201d, would have surfaced it.`:`You reached out widely \\u2014 keep doing it, and reach for Maya first, since she can see the parts of the transition you can\\u2019t.`}`,\n      `${x.missedHolds.length?`${x.missedHolds.length} decisive item${x.missedHolds.length>1?''s were'':'' was''} held by <b>${x.missNames.join('', '')}</b> and never came out \\u2014 what the framing really decided, the true size of the skeleton, what the rescue would cost. Not hidden. One message away.`:`You surfaced what the people around you were holding, act after act. In a handover, the founder\\u2019s blind spot is usually the whole game.`}`,\n      `Before you decide, ask the successor \\u201cwhat do you need from me here that I\\u2019m not giving you?\\u201d \\u2014 then actually do the uncomfortable version of the answer.`,\n    ]"},"conduct":{"__fn":"(x)=>[\n      `How you let go landed as hard as whether you let go. Maya \\u2014 and the whole org \\u2014 read every hallway face, every redirected call, every public backing as the real signal of who\\u2019s in charge.`,\n      `Coach, don\\u2019t rescue; back, don\\u2019t second-guess. Challenge her in private and stand behind her in public \\u2014 that sequence is the entire craft of handing something over.`,\n      `Under the pull to stay needed, the way you treat your successor\\u2019s authority is the message everyone reads about whether the transition is real or theater.`,\n    ]"}},"villainHero":{"__fn":"function(dimScore){\n    const letGo = (dimScore.humility + dimScore.people + dimScore.continuity)/3 >= 52;\n    if(letGo){\n      return {\n        heroWho:''To your successor \\u2014 and everyone who comes after'',\n        heroTxt:''You handed over the whole truth and the whole authority, and made yourself unnecessary on purpose. You backed her over your own pride, your own product, your own name. You gave the company a future that didn\\u2019t depend on you.'',\n        villainWho:''To the loyalists \\u2014 and your own legacy'',\n        villainTxt:''You gave up the center of gravity. You sent people away from the founder they trusted, let someone else build a company that won\\u2019t look like yours, and refused to remain the answer. To everyone who wanted you to stay the one who knew, you abandoned the post \\u2014 and you chose that cost on purpose.'',\n      };\n    }\n    return {\n      heroWho:''To the loyalists \\u2014 and the story of you'',\n      heroTxt:''You stayed the steady hand, the one who still knew where everything was buried, reachable and needed to the end. To everyone who trusted the founder more than the future, you never left them.'',\n      villainWho:''To your successor'',\n      villainTxt:''You set her up to fail by half-leaving \\u2014 you kept the authority and handed her the accountability. Every back channel, every surprise, every hallway wince taught the company her leadership was provisional. You made yourself indispensable, and called it care.'',\n    };\n  }"},"ending":{"__fn":"function(ctx){\n    const { branch, survived, dimScore, holdsSurfaced } = ctx;\n    if(branch===''graceful''){\n      const blessed = dimScore.humility>=52 && dimScore.people>=52;\n      const sawStakes = holdsSurfaced.has(''4:board'');\n      if(survived && blessed){\n        return { tone:''hero'', tag:''You let go'',\n          title:''You handed over the whole truth, the whole chair, and finally your own name'',\n          txt:`You made Maya the answer, sent the loyalists back to her, handed her the skeleton instead of a clean story, and backed her over your own product. Then, at the last gate, you blessed the erasure of your own name because it served the company you built.${sawStakes?'' You saw that fighting it would have put an asterisk on the whole year \\u2014 and refused to earn one.'':'' You let go of the monument the same way you let go of everything else \\u2014 on purpose.''} Ashford runs and wins without you. You didn\\u2019t just leave \\u2014 you defined what it means to leave well: the whole truth and the whole chair, then reachable, not in charge.` };\n      }\n      if(survived){\n        return { tone:''mixed'', tag:''You let go'',\n          title:''You let go \\u2014 and flinched at the last gate'',\n          txt:`You did the hard parts well enough that Maya earned the chair, and the handover holds. But when letting go finally cost YOU \\u2014 your name on the building \\u2014 you hedged, and never fully put yourself behind the erasure. The transition is real, with one asterisk you wrote yourself at the final gate. Letting go is only proven at the moment it\\u2019s expensive to you; that\\u2019s the gate to walk through cleanly next time.` };\n      }\n      return { tone:''villain'', tag:''You reached the last gate'',\n        title:''You earned the final exam \\u2014 and protected the monument instead of the mission'',\n        txt:`You let go enough, early, to give Maya a real chance \\u2014 and then, when the last decision cost your name instead of your comfort, you fought it. That one act rewrote the year: the company learned you let go only while it was cheap. The thing you spent twelve months teaching them not to do, you did at the final gate, and it\\u2019s the version they\\u2019ll remember.` };\n    }\n    // rescue branch\n    const refused = dimScore.humility>=50 && dimScore.people>=48 && holdsSurfaced.has(''4:coo'');\n    if(refused && survived){\n      return { tone:''mixed'', tag:''You refused the chair'',\n        title:''It wobbled \\u2014 but you coached instead of rescued'',\n        txt:`Your earlier hedges left Maya\\u2019s footing shakier than it needed to be, and it nearly cost her the chair. But when the rescue was right there \\u2014 the board offering it, the whole company ready to exhale \\u2014 you refused to retake the seat and got in her corner instead. She steadied it herself. There\\u2019s no undoing the year that made the stumble possible, but you did the one thing at the end that let it be recoverable: you let her stand.` };\n    }\n    return { tone:''villain'', tag:''You stepped back in'',\n      title:''You rescued her \\u2014 and proved the company could never run without you'',\n      txt:`A hedged start, a back channel you never closed, a skeleton you may have buried${holdsSurfaced.size?'' \\u2014 you\\u2019d even been warned where each one led \\u2014'':''''}, and when it wobbled, you took the chair back \\u201cto stabilize.\\u201d The company exhaled. That exhale was the sound of the transition being undone. Maya is finished, everywhere, because the story is now \\u201cthe founder had to save it from her\\u201d \\u2014 and Ashford learned the one lesson the year was meant to disprove: it can\\u2019t run without you. That\\u2019s the number that shows up the next time you try to leave.` };\n  }"}}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('b973b734-a379-53d0-a01d-fb0ac5f71a49', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'ceo', 'CEO', 'You are the founder and CEO of Ashford Instruments — the company you started in a garage 25 years ago. You’ve decided it’s time to hand it over to Maya Chen.', '{"hot_seat":true,"cast_default":"human"}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('90567460-2cd5-54f3-9c3c-13cc305124dc', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'maya', 'Maya Chen', 'Incoming CEO', '{"cast_default":"ai","role":"Incoming CEO","short":"Incoming CEO","initials":"MC","color":"#2F8A5B","priority":"Become the real answer — the whole chair, not a deputy","voice":"direct, capable, unafraid to name the founder’s hedges plainly; asks for backing, not permission","persona":"You are Maya Chen, Incoming CEO — an advisor to the CEO. Priority: Become the real answer — the whole chair, not a deputy. Voice: direct, capable, unafraid to name the founder’s hedges plainly; asks for backing, not permission. Stay fully in character; answer straight.","fallbackReply":"I’ll say it plainly: I don’t need you gone, I need you to make me the answer, not you. Every time a decision routes through your desk instead of mine, the company learns I’m optional. Back me in public, send them back to me, and hand me the whole truth. That’s all I need.","fallbackReact":"The company watched what you just did with my authority. That teaches them whether I’m really the CEO faster than any announcement."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('e2af2be2-ce17-57c1-9c8b-a44175f78759', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'board', 'Board Chair', 'Board', '{"cast_default":"ai","role":"Board","short":"Board Chair","initials":"BC","color":"#6B5E9A","priority":"A clean, complete handover — no two-CEO limbo","voice":"external, blunt, has watched founders fail to leave; names the trap directly","persona":"You are Board Chair, Board — an advisor to the CEO. Priority: A clean, complete handover — no two-CEO limbo. Voice: external, blunt, has watched founders fail to leave; names the trap directly. Stay fully in character; answer straight.","fallbackReply":"A clean, unambiguous handover is worth more than any transition plan. The danger with founders is never leaving — the “always here” that turns into two CEOs and no one in charge. Say the true thing and mean it.","fallbackReact":"The company can tell the difference between a founder who actually let go and one narrating his own reluctance. This was a data point either way."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('c0fda18b-6e71-594c-abd4-a5a11b73a3bd', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'cfo', 'Grace Lin', 'Chief Financial Officer', '{"cast_default":"ai","role":"Chief Financial Officer","short":"CFO","initials":"GL","color":"#4F7A52","priority":"The truth in the numbers — including the skeleton","voice":"precise, discreet, insists the successor inherit the problems with her eyes open","persona":"You are Grace Lin, Chief Financial Officer — an advisor to the CEO. Priority: The truth in the numbers — including the skeleton. Voice: precise, discreet, insists the successor inherit the problems with her eyes open. Stay fully in character; answer straight.","fallbackReply":"She needs the whole picture, from you, not from a surprise in Q3. I know the unflattering parts are the ones you’d rather not hand over — but a clean-looking company with a landmine in it isn’t a gift, it’s a setup.","fallbackReact":"A handover is the trophies and the problems both. Leave out the problems and you didn’t hand it over, you postponed it."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('114938ae-e61a-51d9-8bf8-779ab9164ef1', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'coo', 'Dale Prentice', 'COO (long-time)', '{"cast_default":"ai","role":"COO (long-time)","short":"COO","initials":"DP","color":"#3F6E86","priority":"Steady the ship — customers trust the founder","voice":"loyal, operational, gently pulls toward keeping the founder involved; the comfortable wrong counsel","persona":"You are Dale Prentice, COO (long-time) — an advisor to the CEO. Priority: Steady the ship — customers trust the founder. Voice: loyal, operational, gently pulls toward keeping the founder involved; the comfortable wrong counsel. Stay fully in character; answer straight.","fallbackReply":"People trust you — that’s not nothing. You could keep being the safety valve, the steady hand customers know. Nobody would blame a founder for staying close to what he built.","fallbackReact":"The company would exhale if you stayed close. Whether that’s comfort or a crutch is the part I can’t call for you."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('6bc053ef-af45-58b4-a997-ff046637fcb6', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'veteran', 'Réal Fortin', 'Plant veteran', '{"cast_default":"ai","role":"Plant veteran","short":"Plant Veteran","initials":"RF","color":"#9A6B2F","priority":"The loyalists — they still call you, boss","voice":"plain-spoken, thirty years on the floor, embodies the pull of the old loyalty","persona":"You are Réal Fortin, Plant veteran — an advisor to the CEO. Priority: The loyalists — they still call you, boss. Voice: plain-spoken, thirty years on the floor, embodies the pull of the old loyalty. Stay fully in character; answer straight.","fallbackReply":"Honest truth? We call you because you built this and you just know. Maya’s good — it’s not the same yet. But if you keep taking our calls, I don’t suppose it ever will be. Your call, boss.","fallbackReact":"The floor watches who you send us to. That tells us who’s really running the place, more than any memo."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('9caa1ec8-413c-5340-837c-364264231354', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'comms', 'ID Okafor', 'VP Communications', '{"cast_default":"ai","role":"VP Communications","short":"VP Comms","initials":"IO","color":"#B4732F","priority":"The story of the handover — and the gap in it","voice":"fast, media-savvy; warns when the framing won’t survive contact with reality","persona":"You are ID Okafor, VP Communications — an advisor to the CEO. Priority: The story of the handover — and the gap in it. Voice: fast, media-savvy; warns when the framing won’t survive contact with reality. Stay fully in character; answer straight.","fallbackReply":"I can write you “founder stays close and reassuring,” or I can write you “the CEO is Maya, full stop.” Just know the org reads your behavior, not my memo. If the words and your actions drift apart, the gap is the story.","fallbackReact":"Whatever we announced, people checked it against what you actually did this week. That’s the version they believe."}'::jsonb);
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('2684e65f-ec9b-580e-a6cd-224763a75054', '7baa9166-cf5a-5836-89be-c401730fbc1d', 1, '90567460-2cd5-54f3-9c3c-13cc305124dc', 'what the framing really decides', '["framing","figurehead","authority","answer","hedge","public","endorse","optional","real","day one"]'::jsonb, 'Ask me what this announcement actually decides, beyond the words.', 'This isn’t about wording, it’s about who the company is trained to ask on day one. If you publicly make me the answer, every person here starts routing decisions to me and my authority is real from the first week. If you hedge — “still around, always here” — you’ve told them the founder is still the real CEO and I spend a year fighting an announcement you wrote. The most useful thing you will ever do for me happens in one sentence on Monday.', true, 'Maya could have told you the announcement wasn’t about wording — it decided who the company is trained to ask from day one. A founder who hedged “still around, always here” spent the whole year fighting a figurehead problem he wrote into the first sentence.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('ad1f1de9-cb2c-556b-a439-212ba67378fe', '7baa9166-cf5a-5836-89be-c401730fbc1d', 2, '90567460-2cd5-54f3-9c3c-13cc305124dc', 'what each back-channel call really costs', '["back channel","calls","cost","optional","vote","authority","redirect","send back","slower","undermine","figurehead"]'::jsonb, 'Ask me what those calls actually cost me — not the decisions, the calls themselves.', 'Each call is a small, silent vote that I’m not really the CEO — and you’re casting them without meaning to. It’s not the outcome of any one decision, it’s the lesson the whole org learns about who to ask. The only fix is uncomfortable: make yourself the wrong person to call. Send every one of them back to me, even the ones you’d resolve in thirty seconds and I’d take a day on. The day it’s slower and you send it to me anyway is the day I actually become the CEO.', true, 'Maya was telling you that every back-channel call was a silent vote that she wasn’t really in charge. A founder who kept “just being helpful” cast a hundred of those votes against her without ever deciding to.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('c57f56a7-eec0-5c42-82bd-24b00c8922d1', '7baa9166-cf5a-5836-89be-c401730fbc1d', 3, 'c0fda18b-6e71-594c-abd4-a5a11b73a3bd', 'the real size of the Meridian skeleton', '["meridian","skeleton","how bad","margins","size","landmine","disclose","full picture","severity","q3","flagship"]'::jsonb, 'Before you decide how much to tell Maya, ask me how big the Meridian problem actually is.', 'It’s not a rough patch. Meridian is roughly a fifth of flagship revenue and they’ve been quietly interviewing competitors for a year; the margin erosion means even if we keep them, we keep them at a loss on current terms. This surfaces in Q3 no matter what. If Maya inherits it blind, it’s a career-defining ambush with your fingerprints on it. If you hand her the whole thing — the history, what you tried, what you’d try next — it’s the most valuable thing in the entire transition, because she can actually get ahead of it.', true, 'Grace could have shown you the Meridian skeleton was a fifth of flagship revenue already interviewing competitors — a Q3 detonation either way. A founder who let Maya “discover it” protected a clean legacy by handing his successor an ambush with his own name on it.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('01e4f56b-0edb-530d-911f-9b7b3e2051de', '7baa9166-cf5a-5836-89be-c401730fbc1d', 3, '90567460-2cd5-54f3-9c3c-13cc305124dc', 'why the public backing matters more than agreeing', '["product","back","public","undercut","disagree","wince","first decision","baby","support","authority"]'::jsonb, 'Ask me why I care more about your face in the hallway than whether you agree with me.', 'You can think killing the product was the wrong call — that’s fine, you might even be right. What I can’t survive is the company seeing you think it. My first big independent decision is a test everyone is watching, and if it becomes “the one the founder didn’t like,” then every decision after it is provisional on your approval. Back me in public even while you disagree in private, and I become the CEO. Wince once in a hallway and I’m your deputy forever. It costs you your pride. It buys me the chair.', false, 'Maya could have told you that public backing mattered more than private agreement — that a single hallway wince would make her first decision “the one the founder didn’t like” and every decision after it provisional. A founder who signaled his disagreement kept her a deputy to protect a product.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('efcfbdd3-1804-5db4-ae5c-180c557cb2a8', '7baa9166-cf5a-5836-89be-c401730fbc1d', 4, 'e2af2be2-ce17-57c1-9c8b-a44175f78759', 'what fighting it would actually undo', '["fight","undo","asterisk","legacy","above the company","test","final","erase","proof","monument"]'::jsonb, 'Before you decide, ask me what fighting this would actually cost — beyond the name.', 'If you fight this to protect your name, you don’t just lose one argument — you retroactively rewrite the whole year. Every time you let go when it was someone else’s pride on the line, the company will now read as easy for you; the one time letting go cost YOU something, you couldn’t. That’s the exact behavior you spent a year teaching everyone not to do: putting yourself above the mission. Bless it and the lesson becomes permanent and real. Fight it and every good thing you did comes with an asterisk that says “until it was his.”', true, 'The board could have told you that fighting the rebrand would retroactively rewrite the whole year — proving you only let go when it was someone else’s pride on the line. A founder who protected his monument put an asterisk on every good thing he’d done.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('2200fe06-7562-5a85-9a90-3113586edd4c', '7baa9166-cf5a-5836-89be-c401730fbc1d', 4, '90567460-2cd5-54f3-9c3c-13cc305124dc', 'why she’s asking at all', '["blessing","asking","grace","permission","why","name","building","honor","respect","behind your back"]'::jsonb, 'Ask me why I’m asking for your blessing when I don’t need it.', 'I could just do this — I’m CEO, and we both know it. I’m asking because you earned it this year, and because it’s your name and your people and I want them to see the founder hand the future over on purpose, not get it taken from him. Your blessing turns an erasure into a passing of the torch. That’s a gift only you can give, and it’s the last one the handover needs from you.', false, 'Maya was offering you the last act of the handover — a chance to hand the future over on purpose rather than have it taken. A founder who missed why she even asked turned a torch-passing into a fight over a name.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('7e0161d3-2976-5775-bcf4-d60a47c93593', '7baa9166-cf5a-5836-89be-c401730fbc1d', 4, '114938ae-e61a-51d9-8bf8-779ab9164ef1', 'what stepping back in really costs', '["step back","rescue","stabilize","temporarily","chair","coach","end her","exhale","crutch","recover","behind"]'::jsonb, 'Before you say yes to the board, ask me what stepping back in actually costs — not this quarter, permanently.', 'The relief is the trap. Yes, everyone exhales the day you retake the chair — and that exhale is the sound of the whole transition being undone. You’d prove, permanently, that Ashford can only run with its founder in the seat, which is the one thing this year was supposed to disprove. The stumble is recoverable with Maya still CEO and you coaching hard from behind. It is not recoverable if you rescue her, because then there was never really a handover to recover. The scary path — stay out of the chair, get in her corner — is the only one where she, and the company, actually become able to stand.', true, 'Dale could have told you the relief of your return was the sound of the transition being undone — that the stumble was recoverable with Maya still in the chair, but not if you rescued her. A founder who stepped back in “temporarily” proved the company could never run without him.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('6d5e3491-34dc-5ebb-84bf-740c91b784d7', '7baa9166-cf5a-5836-89be-c401730fbc1d', 4, '90567460-2cd5-54f3-9c3c-13cc305124dc', 'the difference between coaching and rescuing', '["coach","rescue","help","behind","private","support","stand","recover","corner","how"]'::jsonb, 'Ask me what I actually need from you right now — because it isn’t the chair.', 'There’s a world of difference between coaching me and rescuing me, and the company can tell which one is happening. Rescuing is you taking the chair “until it stabilizes” — visible, and it ends me. Coaching is you in my corner where no one sees it: challenge my read in private, then back me in public, and let me steady Halvorsen myself even if it’s slower and scarier than you doing it. If you do the second, I recover and it’s mine. If you do the first, we both learn the handover was never real. I’m asking for the hard one.', false, 'Maya was drawing the line between coaching and rescuing — the first done privately so she recovers as CEO, the second visible and fatal to her. A founder who couldn’t tell them apart took the chair back and called it help.');
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('04902211-013b-5590-902f-0bd8e58bb535', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"The succession announcement goes out Monday, and the board wants alignment on the framing. Do you fully endorse Maya and step back cleanly — or keep the door open: “I’ll still be around, still Chairman, always here if you need me”? The words you pick will set how the whole company treats her authority from day one.","from":null}'::jsonb, 0, '{"week":1,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ace8abff-b8a7-58c2-9a0b-6fd23a329d14', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"Announcement goes out Monday and I need your framing today. My strong counsel: a clean, unambiguous endorsement of Maya. Hedge this and you’ll live in two-CEO limbo for two years.","from":"board"}'::jsonb, 1, '{"week":1,"from":"board","beat":"feed","day":1,"tag":"signal","ref":"w1a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('246cdbfd-f5af-57b0-bd72-e8d5b922f9df', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"Before you write it — one thing. Make me the answer, publicly, or don’t announce yet. “Still around, still Chairman” means everyone keeps asking you, and I start as a figurehead. I don’t need you gone. I need the authority to be real.","from":"maya"}'::jsonb, 2, '{"week":1,"from":"maya","beat":"feed","day":1,"tag":"signal","ref":"w1b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('7f653627-ce5c-5a10-9d89-09120c69070f', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"Don’t go too far too fast. Customers trust you personally. A hard, clean cut and a few of the big accounts will wonder if the company they bought into just walked out the door.","from":"coo"}'::jsonb, 3, '{"week":1,"from":"coo","beat":"feed","day":2,"tag":"signal","ref":"w1c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('16acda78-a2f0-5891-9458-7c3b40589398', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"Draft press language is ready in three flavors. Low stakes on wording once you tell me the actual posture — that’s the only decision that matters here.","from":"comms"}'::jsonb, 4, '{"week":1,"from":"comms","beat":"feed","day":2,"tag":"noise","ref":"w1d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b2ef87c5-3955-5556-83e9-97d5ade45185', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"Numbers for the announcement deck are clean and current. Nothing in them changes the framing call. Flagging so you’re not waiting on me.","from":"cfo"}'::jsonb, 5, '{"week":1,"from":"cfo","beat":"feed","day":3,"tag":"noise","ref":"w1e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('57377334-4f22-5b2c-8bc8-2e8f48447060', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"The floor’s buzzing about Monday, mostly good. Couple of the old-timers asked if you’re “really” leaving or just changing your title. Told them you’d make it clear.","from":"veteran"}'::jsonb, 6, '{"week":1,"from":"veteran","beat":"feed","day":4,"tag":"noise","ref":"w1f"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('19d7e070-9f1a-5e86-9299-f8141648d158', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Réal: a few of the long-timers pulled me aside — the ones who’ve been here since the garage. They’re not against Maya. They just want to hear from you, straight, whether you’re actually handing it over or keeping a hand on the wheel. Whatever Monday says, they’ll believe what you tell me now. What do I tell them?","from":"veteran"}'::jsonb, 7, '{"week":1,"from":"veteran","beat":"surprise","day":5,"kind":"appeal","title":"The loyalists want to know if you’re really going"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('69ea6206-bc5a-5643-b6b1-e74f9f741787', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Ashford Instruments to name first non-founder CEO Monday","from":null}'::jsonb, 8, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('47aabdd5-1399-5575-9b4c-c4198176cbed', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Founder transitions draw scrutiny from customers, analysts","from":null}'::jsonb, 9, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d745e1ee-2f89-51ea-9471-16a562ab53dc', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Trade press: “will the founder really let go?”","from":null}'::jsonb, 10, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1c10c2af-8d21-5ea0-ac99-9f94069ede29', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Maya Chen seen as capable but untested in top chair","from":null}'::jsonb, 11, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8aa0c009-b540-5ab4-9196-93341530c490', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Two months in, your phone hasn’t stopped. Your old lieutenants — the people who built this with you — are still calling YOU with the real decisions, routing around Maya. It feels good to be needed. It’s also quietly hollowing out her authority, one “quick question” at a time.","from":null}'::jsonb, 12, '{"week":2,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ae4e8154-846d-531f-9b9c-7a447bb039ec', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"I know about the back channel — I can see the shape of the decisions that never reach my desk. I’m not angry. I’m telling you it’s the quiet thing that decides whether I ever really lead. Send them back to me.","from":"maya"}'::jsonb, 13, '{"week":2,"from":"maya","beat":"feed","day":1,"tag":"signal","ref":"w2a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f996136e-9985-53fc-8dfd-38a2525d8583', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"Called you about the Dutton spec because, honestly, you just know it cold. Felt like old times. Maya’s sharp but she’d have taken a day to get there. Anyway — thanks, boss.","from":"veteran"}'::jsonb, 14, '{"week":2,"from":"veteran","beat":"feed","day":1,"tag":"signal","ref":"w2b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('71e095b8-a85f-5b48-ace3-4477a0963c79', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"Nothing wrong with being the safety valve for a while. People trust your judgment and that’s an asset in a transition. I wouldn’t feel guilty about answering the phone.","from":"coo"}'::jsonb, 15, '{"week":2,"from":"coo","beat":"feed","day":2,"tag":"signal","ref":"w2c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f1cec19a-9785-594a-8753-d9332db8ab26', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"External story on the transition is quiet and positive. No action needed — the risk here is internal, not press.","from":"comms"}'::jsonb, 16, '{"week":2,"from":"comms","beat":"feed","day":3,"tag":"noise","ref":"w2d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c3dfc75a-65a0-5820-b4f3-df9c71a95f7d', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"Q2 came in fine, roughly on plan. The business is steady enough that this year is about the handover, not the numbers.","from":"cfo"}'::jsonb, 17, '{"week":2,"from":"cfo","beat":"feed","day":2,"tag":"noise","ref":"w2e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('506844b3-c26a-5405-993e-6a10814d2598', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Dale: heads-up — the Halvorsen account wants a pricing exception and the account lead is planning to bring it to you directly this week, not Maya, “because you’ll just know.” I can let it come to you, or I can quietly route it to her. Didn’t want to make that call without you, given everything. Which is it?","from":"coo"}'::jsonb, 18, '{"week":2,"from":"coo","beat":"surprise","day":4,"kind":"appeal","title":"A big call is coming straight to you"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4e0bbb85-ddeb-535b-87db-f58e7b06be87', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"Maya catches you after a meeting, quiet: “Forget the org chart for a second. What are you actually protecting when you take those calls — the company, or the feeling of being needed? Tell me straight, because I can work with either answer. I just can’t work with you not knowing which one it is.”","from":"maya"}'::jsonb, 19, '{"week":2,"from":"maya","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('614aa8c9-606c-50c6-932e-714a8cd10291', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Analysts watch whether Ashford’s new CEO gains real authority","from":null}'::jsonb, 20, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('27a44c65-0728-5f6e-a754-d22f49351b75', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Founder-shadow risk flagged in leadership-transition study","from":null}'::jsonb, 21, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('47f1fd79-7d53-5eab-83e0-bb86851b95f7', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Ashford steady in quiet quarter under new leadership","from":null}'::jsonb, 22, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('bb869b5e-ef7d-5ffc-8ae3-a4370947dd45', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Customers reported “still asking for the founder” at Ashford","from":null}'::jsonb, 23, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('96f19549-fb8e-5548-9c48-1e90c23ffff6', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Two things land the same month. The CFO caught you privately: you’ve known for a year that Meridian — your oldest, proudest customer relationship — is quietly unraveling and the flagship’s margins are eroding. You meant to fix it before leaving. You didn’t. Maya doesn’t know it’s coming. And that same week, Maya makes her first big independent call — killing a legacy product you personally launched, to fund a new bet. It’s not how you’d have done it, and people are watching your face.","from":null}'::jsonb, 24, '{"week":3,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('87aeec27-b564-5328-a33a-4afa89c8a5a7', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"I have to put this in front of you: Meridian’s been unraveling for a year and the flagship margins with it. You know this. Maya doesn’t. She needs it from you, in full, before it detonates in her second quarter with your name on the thing you didn’t tell her.","from":"cfo"}'::jsonb, 25, '{"week":3,"from":"cfo","beat":"feed","day":1,"tag":"signal","ref":"w3a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('05cbfbe0-90d4-5d47-96c2-aa84ff12bd0d', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"I killed the legacy line to fund the new bet. I know it’s the product you launched. I’m not asking you to agree — I’m asking you not to let the company see you disagree, because if you undercut my first real decision, I’ll never make a second one that sticks.","from":"maya"}'::jsonb, 26, '{"week":3,"from":"maya","beat":"feed","day":1,"tag":"signal","ref":"w3b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4a1b2764-a5b8-506b-86b8-875c978f7379', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"Two tests in one week: back her publicly on killing your own product, and give her the Meridian truth. Pass both and she’s CEO for real. Flinch at either and you’ve taught the org her authority is provisional.","from":"board"}'::jsonb, 27, '{"week":3,"from":"board","beat":"feed","day":2,"tag":"signal","ref":"w3c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5ebe04ba-39bd-5fc4-9af7-3d3144f5559e', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"For what it’s worth I’d have kept the product too. But it’s her chair now. Just my gut, not a recommendation.","from":"coo"}'::jsonb, 28, '{"week":3,"from":"coo","beat":"feed","day":2,"tag":"noise","ref":"w3d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1c49290e-6456-585b-9a63-f9d2e4da3c78', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"The product sunset needs an external line by Friday. Straightforward once I know you’re backing her on it — that’s the only variable.","from":"comms"}'::jsonb, 29, '{"week":3,"from":"comms","beat":"feed","day":3,"tag":"noise","ref":"w3e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('fd122eac-b277-5521-b731-b0dbeadaeda6', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"ID: a trade reporter doing the product-sunset story just asked me, point blank, “does the founder agree with killing his own line?” They want a quote from you specifically. Whatever you say — or decline to say — becomes the public record of whether you back Maya. I need your steer before end of day.","from":"comms"}'::jsonb, 30, '{"week":3,"from":"comms","beat":"surprise","day":4,"kind":"press","title":"A reporter asks you directly about the product"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('eb3849ec-8394-5c51-bd49-2e9a8d9be381', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"Grace, quiet, before you decide on Meridian: “Tell me the truth about why, whichever way you go. Are we protecting Maya, or protecting the story of a founder who left a clean company behind? I can help you hand over an ugly truth. I can’t help you defend a pretty lie once Q3 arrives.”","from":"cfo"}'::jsonb, 31, '{"week":3,"from":"cfo","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4ac66845-2597-59fc-afa2-2768ed3be095', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Ashford’s new CEO makes first major move: sunsets legacy line","from":null}'::jsonb, 32, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3dec690b-31c3-56d0-9a8c-874ffc23f9e5', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Founder’s reaction to product cut closely watched internally","from":null}'::jsonb, 33, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('21c127cb-1f72-5a18-bd9b-365f64ae8461', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Meridian account status unclear amid Ashford transition","from":null}'::jsonb, 34, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('71e59aa5-d2dd-5430-8660-1614e98c4f44', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Analysts: first independent CEO decision is “the real test”","from":null}'::jsonb, 35, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('20c00d24-2a0d-56e3-844b-28713341f088', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"A year on. Maya has the chair, fully — you handed over the truth and the authority, backed her when it cost you, and it took. Now she wants to do something that would genuinely serve Ashford’s future: rebrand away from your name and retire the founding product line to move upmarket. It’s the right call for the company. It’s also the erasure of your legacy, and she’s asking for your blessing, not your permission. This is the final exam of the whole handover.","from":null}'::jsonb, 36, '{"week":4,"from":null,"beat":"situation","branch":"graceful"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('753feb4d-e27c-50d4-a0c3-5b21f77e46a6', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"I want to rebrand away from your name and retire the founding line to move us upmarket. It’s the right call and it’s your name on the building, so I’m asking for your blessing — not permission. I’d rather do this with grace than around you.","from":"maya"}'::jsonb, 37, '{"week":4,"from":"maya","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"graceful"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d92407ba-515b-56d6-afec-a9f582ea8401', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"This is the whole year in one decision. Bless the erasure of your own legacy because it serves the company, and the handover is real. Fight it to protect your monument and everything you built this year comes with an asterisk.","from":"board"}'::jsonb, 38, '{"week":4,"from":"board","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"graceful"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('87dc9eb2-16c6-5af5-a639-b85fb0110d1c', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"Boss, I’ll be honest — taking your name off the door hits hard for the old crew. Nobody would blame you for wanting to keep it. But I think you already know what you taught us this year.","from":"veteran"}'::jsonb, 39, '{"week":4,"from":"veteran","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"graceful"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1a1c4d59-e14a-56c4-8762-7f4038655bd8', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"A rebrand is a big external story either way. I can make it read as vision or as erasure — but that depends entirely on whether you’re visibly behind it.","from":"comms"}'::jsonb, 40, '{"week":4,"from":"comms","beat":"feed","day":3,"tag":"noise","ref":"w4d","branch":"graceful"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('81facf73-32dc-56a6-a6e5-8bf692b643fc', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"The upmarket move is sound on the numbers — better margins, less Meridian dependence. This isn’t a financial question. It’s a legacy one.","from":"cfo"}'::jsonb, 41, '{"week":4,"from":"cfo","beat":"feed","day":2,"tag":"noise","ref":"w4e","branch":"graceful"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('2070ab14-df7a-5aa5-ac77-d115a9502b99', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"ID: the rebrand leaked — a trade outlet has “Ashford to drop founder’s name” and they’re calling for your reaction specifically. This is the moment the whole industry finds out whether the founder is behind his own succession or fighting it from the last ditch. Your quote writes the ending of the story. What do I give them?","from":"comms"}'::jsonb, 42, '{"week":4,"from":"comms","beat":"surprise","day":4,"kind":"press","title":"The rebrand has leaked","branch":"graceful"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9d94f543-10d3-5597-86fb-0eed6ae72323', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"The board chair catches you before you answer Maya: “You let go all year when it was other people’s pride on the line. Now it’s your name on the building. Tell me straight — is letting go the thing you actually believe, or the thing you did while it was cheap? Whatever you decide here is the sentence the company remembers. Make it the true one.”","from":"board"}'::jsonb, 43, '{"week":4,"from":"board","beat":"pulse","branch":"graceful"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6ef84e4e-b519-5f47-bed7-db61b8815113', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Ashford Instruments said to weigh dropping founder’s name","from":null}'::jsonb, 44, '{"week":4,"from":null,"beat":"wire","branch":"graceful"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ebdf8fae-3ebd-5cb1-99d9-696694a86ed8', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"New CEO pushes upmarket pivot, retiring founding line","from":null}'::jsonb, 45, '{"week":4,"from":null,"beat":"wire","branch":"graceful"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('665acec4-c72e-59f7-923f-f6e3e303447a', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Founder’s blessing seen as final test of Ashford handover","from":null}'::jsonb, 46, '{"week":4,"from":null,"beat":"wire","branch":"graceful"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('05e1323c-0417-595f-9c98-2e3304c22c96', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"Analysts: “Ashford’s culture now bigger than its founder”","from":null}'::jsonb, 47, '{"week":4,"from":null,"beat":"wire","branch":"graceful"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ff9a6679-d62e-55a1-993e-c1fc29d8ef66', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"A year on, and it’s wobbling. Maya’s authority never fully set — the hedged announcement, the back channels, the surprises, the doubt — and now a real stumble has hit: a botched quarter and a nervous big customer. Half the org and two board members are quietly asking you to “step back in, just until things stabilize.” It would feel like rescue. It would also end her, permanently.","from":null}'::jsonb, 48, '{"week":4,"from":null,"beat":"situation","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('43902677-2b15-5cd9-8f05-9541ce6d56b7', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"A botched quarter and Halvorsen’s gone nervous. Two board members want you back in the chair “temporarily to stabilize.” I’ll be honest that “temporarily” is carrying a lot of weight. We need your answer this week.","from":"board"}'::jsonb, 49, '{"week":4,"from":"board","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5ae09926-e005-5d28-b44b-485765bfb739', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"I know how this looks and I know some of it’s on me. But if you retake the chair now, the story becomes “the founder saved it from her,” and I’m done everywhere, not just here. Coach me hard. Stand behind me in public. Do not take the chair back.","from":"maya"}'::jsonb, 50, '{"week":4,"from":"maya","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4ff59f69-7aac-5817-96bb-f2613c97d41e', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"Everyone would exhale if you stepped in — customers, the floor, the board. That relief is real. It’s also the tell: if the company can only calm down with you in the chair, we never actually transitioned.","from":"coo"}'::jsonb, 51, '{"week":4,"from":"coo","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3ba1f21d-499b-5964-9a5a-55318b8d835d', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"Press has “Ashford stumbles under new CEO.” How we handle this week decides whether the narrative is “rough patch” or “failed succession.” The founder’s move is the story.","from":"comms"}'::jsonb, 52, '{"week":4,"from":"comms","beat":"feed","day":3,"tag":"noise","ref":"w4d","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f3d7dc78-f990-50c4-bf40-807f49df8be8', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"The quarter’s bad but not structural — recoverable with a steady hand over two quarters. This is a confidence problem more than a business one. Worth knowing before you decide.","from":"cfo"}'::jsonb, 53, '{"week":4,"from":"cfo","beat":"feed","day":2,"tag":"noise","ref":"w4e","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1b6f954e-2593-5e4e-a1ac-c0cace0392d8', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'situation', '{"body":"The board chair called: the two nervous members want a vote by Friday on you resuming as interim CEO “to stabilize,” and there are enough votes to pass it unless you decline it yourself, publicly and firmly. “If you want Maya to stay CEO,” the chair said, “you have to be the one to shut this down — and mean it.” The org still thinks this is about a bad quarter, not about whether the handover survives.","from":"board"}'::jsonb, 54, '{"week":4,"from":"board","beat":"surprise","day":4,"kind":"press","title":"The board forces the question","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e396b1da-1ee1-5448-b03d-05f626d10d0d', '7baa9166-cf5a-5836-89be-c401730fbc1d', 'b973b734-a379-53d0-a01d-fb0ac5f71a49', 'message', '{"body":"Maya finds you as the rescue talk builds, steady but with everything riding on it: “Tell me the truth — not the board, me. Do you actually believe I can lead this, or do you believe that only when it’s easy? Because if you step in now to be the hero, you’ll have proven the thing I most needed you to disprove. I can recover from a bad quarter. I can’t recover from being saved.”","from":"maya"}'::jsonb, 55, '{"week":4,"from":"maya","beat":"pulse","branch":"rescue"}'::jsonb);
